#!/usr/bin/env bash#SBATCH --job-name=pv1_7b_high_k#SBATCH --partition=dev#SBATCH --nodes=1#SBATCH --gpus-per-node=1#SBATCH --cpus-per-task=8#SBATCH --mem=64G#SBATCH --time=00:55:00#SBATCH --output=logs/pv1_7b_high_k_%j.log#SBATCH --error=logs/pv1_7b_high_k_%j.errset -euo pipefailROOT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"JOB_ID="${SLURM_JOB_ID:-nojob}"JOB_MARKER_DIR="$ROOT_DIR/handoff/job_done"mkdir -p "$JOB_MARKER_DIR" "$ROOT_DIR/logs"# Completion handoff markerwrite_marker() {  local exit_code="$1"  local marker_file="$JOB_MARKER_DIR/job_${JOB_ID}.json"  cat > "$marker_file" << EOF{  "job_id": "$JOB_ID",  "job_name": "pv1_7b_high_k",  "exit_status": $exit_code,  "finished_at": "$(date -u +%Y-%m-%dT%H:%M:%SZ)",  "workdir": "$ROOT_DIR",  "git_commit": "$(cd "$ROOT_DIR" && git rev-parse HEAD 2>/dev/null || echo 'unknown')",  "stdout": "logs/pv1_7b_high_k_${JOB_ID}.log",  "stderr": "logs/pv1_7b_high_k_${JOB_ID}.err",  "result_csv": "results/precision_throughput/exp3_real_sum_specialized_precision_throughput_exp2k16.csv",  "highk_results": "results/exp3_real_specialized_sum_highk",  "highk_artifacts": "results/exp3_artifacts_k16",  "next_action": "Review marker and inspect result CSV for coverage gaps"}EOF}trap 'write_marker $?' EXIT# ============================================================================# Phase 1: Verify Hardware# ============================================================================echo "[$(date)] [PV1-7B] Phase 1: Hardware verification"gpu_name=$(nvidia-smi --query-gpu=name --format=csv,noheader | head -n 1)if [[ ! "$gpu_name" =~ H200 ]]; then  echo "ERROR: Not running on H200, got: $gpu_name" >&2  exit 2fiecho "[$(date)] [PV1-7B] ✓ H200 verified"# ============================================================================# Phase 2: Setup environment# ============================================================================echo "[$(date)] [PV1-7B] Phase 2: Environment setup"module load miniconda3/26.1.1 cuda/12.6 >/dev/null 2>&1 || trueeval "$(conda shell.bash hook)"conda activate gpu-byteplane-scan >/dev/null 2>&1which nvcc >/dev/null && echo "[$(date)] [PV1-7B] ✓ CUDA available"# ============================================================================# Phase 3: Build encoder and Exp3 benchmark# ============================================================================echo "[$(date)] [PV1-7B] Phase 3: Building tools"BUILD_DIR_EXP3="$ROOT_DIR/build/exp3"mkdir -p "$BUILD_DIR_EXP3"cd "$ROOT_DIR"cmake -S "$ROOT_DIR/benchmarks/experiment3" -B "$BUILD_DIR_EXP3" \  -DCMAKE_BUILD_TYPE=Release -DCMAKE_CUDA_ARCHITECTURES=90 >/dev/null 2>&1cmake --build "$BUILD_DIR_EXP3" -j8 >/dev/null 2>&1ENCODER="$BUILD_DIR_EXP3/export_encoded_dev_layout"if [[ ! -x "$ENCODER" ]]; then  echo "ERROR: Encoder build failed" >&2  exit 1fiecho "[$(date)] [PV1-7B] ✓ Build complete"# ============================================================================# Phase 4: Re-encode Uniform and Zipfian with k=16 support# ============================================================================echo "[$(date)] [PV1-7B] Phase 4: Re-encoding datasets for k=16"ENCODED_ROOT_K16="$ROOT_DIR/results/exp3_artifacts_k16"mkdir -p "$ENCODED_ROOT_K16"for dataset in uniform zipfian; do  INPUT_FILE="/work/u4063895/datasets/synthetic/dev/${dataset}.f64le.bin"  if [[ ! -f "$INPUT_FILE" ]]; then    echo "ERROR: Input file not found: $INPUT_FILE" >&2    exit 1  fi  echo "[$(date)] [PV1-7B] Re-encoding $dataset..."  "$ENCODER" \    --input "$INPUT_FILE" \    --output-root "$ENCODED_ROOT_K16" \    --dataset "$dataset" \    --segment-size 4096 \    2>&1 | grep -E "Writing|max_plane_count" || true  # Verify manifest was created  if [[ ! -f "$ENCODED_ROOT_K16/$dataset/manifest.json" ]]; then    echo "ERROR: Failed to re-encode $dataset" >&2    exit 1  fi  max_k=$(grep max_plane_count "$ENCODED_ROOT_K16/$dataset/manifest.json" | grep -oE '[0-9]+' | tail -1)  echo "[$(date)] [PV1-7B] ✓ $dataset: max_plane_count=$max_k"done# ============================================================================# Phase 5: Run Exp3 High-k Throughput Measurements# ============================================================================echo "[$(date)] [PV1-7B] Phase 5: Running Exp3 benchmarks"RESULTS_HIGHK="$ROOT_DIR/results/exp3_real_specialized_sum_highk"mkdir -p "$RESULTS_HIGHK"run_exp3_highk() {  local dataset="$1"  local refine_max="15"  # k=1..16, refine_max=15  echo "[$(date)] [PV1-7B] Exp3 $dataset: k=1..16"  export MODE="encoded_dev_subcolumns"  export REAL_KERNEL_VARIANT="specialized"  export ENCODED_ROOT="$ENCODED_ROOT_K16"  export REFINE_MIN="0"  export REFINE_MAX="$refine_max"  export VALIDATE="1"  export WARMUP="10"  export ITERS="200"  export RESULTS_BASE="$RESULTS_HIGHK"  export CSV_NAME="throughput.csv"  export RUN_DESC="Specialized real-data SUM throughput on ${dataset}; sweep k=1..16 [PV1-7B]."  "$ROOT_DIR/scripts/legacy/root_runners/run_exp3.sh" 2>&1 | tail -20  echo "[$(date)] [PV1-7B] ✓ $dataset completed"}run_exp3_highk uniformrun_exp3_highk zipfian# ============================================================================# Phase 6: Extract and merge high-k results# ============================================================================echo "[$(date)] [PV1-7B] Phase 6: Merging results"# Find the two most recent run directoriesuniform_rundir=$(cd "$RESULTS_HIGHK" && ls -td run_* 2>/dev/null | head -2 | tail -1)zipfian_rundir=$(cd "$RESULTS_HIGHK" && ls -td run_* 2>/dev/null | head -1)UNIFORM_CSV="$RESULTS_HIGHK/$uniform_rundir/throughput.csv"ZIPFIAN_CSV="$RESULTS_HIGHK/$zipfian_rundir/throughput.csv"if [[ ! -f "$UNIFORM_CSV" ]] || [[ ! -f "$ZIPFIAN_CSV" ]]; then  echo "ERROR: High-k throughput CSVs not found" >&2  exit 1fiecho "[$(date)] [PV1-7B] Merging Uniform and Zipfian high-k rows..."python3 << 'PYTHON_SCRIPT'import csvimport sysfrom pathlib import Pathroot_dir = Path("/home/u4063895/workspace/gpu-byteplane-scan-experiments")uniform_csv = Path(sys.argv[1])zipfian_csv = Path(sys.argv[2])join_csv = root_dir / "results/precision_throughput/exp3_real_sum_specialized_precision_throughput_exp2k16.csv"exp2_extended_csv = root_dir / "results/exp2_extended_sum_k16/results/metrics.csv"# Read current join CSVcurrent_rows = []header = Nonewith join_csv.open() as f:    reader = csv.DictReader(f)    header = reader.fieldnames    for row in reader:        current_rows.append(row)# Read Exp2 error dataexp2_data = {}with exp2_extended_csv.open() as f:    reader = csv.DictReader(f)    for row in reader:        key = (row['dataset'], int(row['k']))        exp2_data[key] = row# Extract high-k rows from new measurementsnew_rows = []for csv_file, dataset, min_k, max_k in [    (uniform_csv, 'Uniform', 11, 16),    (zipfian_csv, 'Zipfian', 12, 16),]:    with csv_file.open() as f:        reader = csv.DictReader(f)        for row in reader:            k = int(row['k'])            if min_k <= k <= max_k:                exp2_key = (dataset, k)                if exp2_key in exp2_data:                    exp2_row = exp2_data[exp2_key]                    out_row = {                        'dataset': dataset,                        'aggregation': 'sum',                        'k': str(k),                        'throughput_billion_rows_per_sec': row.get('billion_rows_per_sec', ''),                        'throughput_logical_GBps': row.get('logical_GBps', ''),                        'exp3_kernel_path': row.get('kernel_path', 'specialized_rowpack16'),                        'exp3_gpu_approx_sum': row.get('gpu_approx_sum', ''),                        'exp3_cpu_approx_sum': row.get('cpu_approx_sum', ''),                        'exp3_abs_cpu_gpu_diff': row.get('abs_cpu_gpu_diff', ''),                        'exp2_abs_error': exp2_row.get('abs_error', ''),                        'exp2_bound': exp2_row.get('bound', ''),                        'exp2_gap': exp2_row.get('gap', ''),                        'exp2_relative_error': exp2_row.get('relative_error', ''),                        'segment_rows': row.get('segment_rows', ''),                        'max_plane_count': row.get('max_plane_count', ''),                        'gpu_tag': row.get('gpu_tag', 'H200'),                        'exp2_exact': exp2_row.get('exact', ''),                        'exp2_approx': exp2_row.get('approx', ''),                        'exp2_threshold': exp2_row.get('threshold', ''),                        'exp3_refinement_depth': row.get('refinement_depth', ''),                        'exp3_logical_subcolumns_read': row.get('logical_subcolumns_read', ''),                        'exp3_validated': row.get('validated', 'true'),                    }                    new_rows.append(out_row)# Merge: replace any existing high-k rows, add new onesfinal_rows = []for row in current_rows:    dataset = row['dataset']    k = int(row['k'])    should_replace = any(        nr['dataset'] == dataset and int(nr['k']) == k        for nr in new_rows    )    if should_replace:        final_rows.append(next(            nr for nr in new_rows            if nr['dataset'] == dataset and int(nr['k']) == k        ))    else:        final_rows.append(row)for new_row in new_rows:    is_existing = any(        r['dataset'] == new_row['dataset'] and int(r['k']) == int(new_row['k'])        for r in current_rows    )    if not is_existing:        final_rows.append(new_row)# Write updated join CSVwith join_csv.open('w', newline='') as f:    writer = csv.DictWriter(f, fieldnames=header)    writer.writeheader()    writer.writerows(final_rows)print(f"Added/updated {len(new_rows)} high-k rows, total: {len(final_rows)}")PYTHON_SCRIPT} "$UNIFORM_CSV" "$ZIPFIAN_CSV"# ============================================================================# Phase 7: Verification# ============================================================================echo "[$(date)] [PV1-7B] Phase 7: Final verification"python3 << 'VERIFY_SCRIPT'import csvfrom pathlib import Pathjoin_csv = Path("results/precision_throughput/exp3_real_sum_specialized_precision_throughput_exp2k16.csv")coverage = {}with join_csv.open() as f:    reader = csv.DictReader(f)    for row in reader:        dataset = row['dataset']        k = int(row['k'])        if dataset not in coverage:            coverage[dataset] = set()        coverage[dataset].add(k)print("\n[PV1-7B] Final Coverage:")for dataset in sorted(coverage.keys()):    ks = sorted(coverage[dataset])    print(f"  {dataset:15} k={min(ks)}..{max(ks)} ({len(ks)} rows)")expected = {    'Heavy-tailed': set(range(1, 17)),    'Sensor': set(range(1, 8)),    'Uniform': set(range(1, 17)),    'Zipfian': set(range(1, 17)),}gaps = {}for dataset, expected_ks in expected.items():    actual_ks = coverage.get(dataset, set())    gap = expected_ks - actual_ks    if gap:        gaps[dataset] = gapif gaps:    print("\n[WARNING] Coverage gaps remain:")    for dataset, ks in sorted(gaps.items()):        print(f"  {dataset}: k={sorted(ks)}")else:    print("\n[SUCCESS] All coverage gaps closed!")total = sum(len(ks) for ks in coverage.values())print(f"\nTotal rows: {total}")VERIFY_SCRIPT}echo "[$(date)] [PV1-7B] Job complete"